#include <iostream>
#include <string>
#include <unordered_map>
using namespace std;struct P{int s1,s2;};int solve(string s1,int n1,string s2,int n2){bool seenChar[256]{};for(char c:s1)seenChar[(unsigned char)c]=true;for(char c:s2)if(!seenChar[(unsigned char)c])return 0;unordered_map<int,P> seen;int s1c=0,s2c=0,idx2=0,prefixS1=0,prefixS2=0,loopS1=0,loopS2=0;for(;;){s1c++;for(char c:s1)if(c==s2[idx2]){idx2++;if(idx2==s2.size()){s2c++;idx2=0;}}if(s1c==n1)return s2c/n2;auto it=seen.find(idx2);if(it!=seen.end()){prefixS1=it->second.s1;prefixS2=it->second.s2;loopS1=s1c-prefixS1;loopS2=s2c-prefixS2;break;}seen[idx2]={s1c,s2c};}int ans=prefixS2,remain=n1-prefixS1;ans+=(remain/loopS1)*loopS2;int rest=remain%loopS1;while(rest--){for(char c:s1)if(c==s2[idx2]){idx2++;if(idx2==s2.size()){ans++;idx2=0;}}}return ans/n2;}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int t;if(!(cin>>t))return 0;for(int tc=0;tc<t;tc++){string s1,s2;int n1,n2;cin>>s1>>n1>>s2>>n2;if(tc)cout<<"\n\n";cout<<solve(s1,n1,s2,n2);}}
